  <svg viewBox="0 0 700 400" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
    <text x="20" y="28" fill="#fafafa" font-size="14" font-weight="700" font-family="sans-serif">Le boom-et-effondrement de la TVL de Plasma vs. le nouveau marché Wildcat · Juil 2026</text>
    <g font-family="sans-serif">
      <text x="20" y="55" fill="#a1a1aa" font-size="13" font-weight="700">① Trajectoire de la TVL de Plasma (sept-nov 2025)</text>
      <line x1="60" y1="180" x2="640" y2="180" stroke="rgba(255,255,255,.15)" stroke-width="1" stroke-dasharray="4,4"/>
      <path d="M100,178 L280,80 L460,178 L600,168" fill="none" stroke="#a78bfa" stroke-width="2.5"/>
      <circle cx="100" cy="178" r="6" fill="#a78bfa"/>
      <circle cx="280" cy="80" r="6" fill="#4ade80"/>
